private class BluetoothCodecReader: FlutterStandardReader {
  override func readValue(ofType type: UInt8) -> Any? {
    switch type {
      case 128:
        return BluetoothStateModel.fromList(self.readValue() as! [Any?])
      case 129:
        return DeviceModel.fromList(self.readValue() as! [Any?])
      case 130:
        return DeviceModel.fromList(self.readValue() as! [Any?])
      case 131:
        return DeviceStateModel.fromList(self.readValue() as! [Any?])
      case 132:
        return DfuConfig.fromList(self.readValue() as! [Any?])
      case 133:
        return WriteStateModel.fromList(self.readValue() as! [Any?])
      default:
        return super.readValue(ofType: type)
    }
  }
}

private class BluetoothCodecWriter: FlutterStandardWriter {
  override func writeValue(_ value: Any) {
    if let value = value as? BluetoothStateModel {
      super.writeByte(128)
      super.writeValue(value.toList())
    } else if let value = value as? DeviceModel {
      super.writeByte(129)
      super.writeValue(value.toList())
    } else if let value = value as? DeviceModel {
      super.writeByte(130)
      super.writeValue(value.toList())
    } else if let value = value as? DeviceStateModel {
      super.writeByte(131)
      super.writeValue(value.toList())
    } else if let value = value as? DfuConfig {
      super.writeByte(132)
      super.writeValue(value.toList())
    } else if let value = value as? WriteStateModel {
      super.writeByte(133)
      super.writeValue(value.toList())
    } else {
      super.writeValue(value)
    }
  }
}

private class BluetoothCodecReaderWriter: FlutterStandardReaderWriter {
  override func reader(with data: Data) -> FlutterStandardReader {
    return BluetoothCodecReader(data: data)
  }

  override func writer(with data: NSMutableData) -> FlutterStandardWriter {
    return BluetoothCodecWriter(data: data)
  }
}

class BluetoothCodec: FlutterStandardMessageCodec {
  static let shared = BluetoothCodec(readerWriter: BluetoothCodecReaderWriter())
}

